import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { RestaurantPublicService, PublicRestaurant } from '../../../services/restaurant-public.service';
import { GeographyService, Province } from '../../../services/Base/geography.service';
import { AuthService } from '../../../services/Base/auth.service';
import { firstValueFrom } from 'rxjs';                
import { SupabaseService } from '../../../services/Base/supabase.service';

@Component({
  selector: 'app-restaurant-list',
  templateUrl: './restaurant-list.html',
  styleUrls: ['./restaurant-list.css'],
  imports: [CommonModule, FormsModule]
})
export class RestaurantList implements OnInit {
  private restaurantPublicService = inject(RestaurantPublicService);
  private geographyService = inject(GeographyService);
  private authService = inject(AuthService);
  private supabaseService = inject(SupabaseService);
  private router = inject(Router);

  restaurants: PublicRestaurant[] = [];
  restaurantFloorPlansMap = new Map<string, { id: string; name: string }[]>();
  filteredRestaurants: PublicRestaurant[] = [];
  loading = true;
  imageErrorCount = 0;
  maxRetries = 2;

  // Filtri
  searchQuery = '';
  selectedCuisine = '';
  cuisineTypes: string[] = [];
  regions: string[] = [];
  filteredProvinces: Province[] = [];
  selectedRegion = '';
  selectedProvince = '';
  allProvinces: Province[] = [];   

  // Stato per la modale mappe
  showMapModal = false;
  selectedRestaurantName = '';
  restaurantMaps: { id: string; name: string; description?: string }[] = [];
  loadingMaps = false;

  // Paginazione
  currentPage = 1;
  pageSize = 9;

async ngOnInit() {
  // 1. Carica ristoranti
  this.restaurants = await this.restaurantPublicService.loadRestaurantsByCuisine();
  this.filteredRestaurants = [...this.restaurants];

  // 2. Carica province e regioni (da GeographyService)
  const provinces = await firstValueFrom(this.geographyService.getFilteredProvinces());
  this.allProvinces = provinces;
  this.regions = [...new Set(provinces.map(p => p.region))].sort();

  // 3. Imposta il filtro di default = provincia dell'utente
  await this.setDefaultUserProvince(provinces);

  // 4. Applica i filtri iniziali
  this.filterRestaurants();
  await this.loadFloorPlansForCurrentPage();


  // 5. Estrai i tipi di cucina
const allCuisines = this.restaurants
  .flatMap(r => r.additional_info?.cuisine_types || [])
  .map(c => c.trim()) // ← normalizza
  .filter((value, index, self) => self.indexOf(value) === index)
  .sort();
  this.cuisineTypes = allCuisines;

  this.loading = false;
}


  // Filtra i ristoranti in base alla ricerca e ai filtri
  filterRestaurants() {
    let filtered = this.restaurants;

    // Filtro testo
    if (this.searchQuery) {
      const query = this.searchQuery.toLowerCase();
      filtered = filtered.filter(r =>
        r.name?.toLowerCase().includes(query) ||
        r.address?.toLowerCase().includes(query) ||
        r.description?.toLowerCase().includes(query) ||
        // Cerca anche nei tipi di cucina
        r.additional_info?.cuisine_types?.some(c => c.toLowerCase().includes(query))
      );
    }

    // Filtro cucina (basato su array)
    if (this.selectedCuisine) {
      filtered = filtered.filter(r => 
        r.additional_info?.cuisine_types?.some(c => 
          c.toLowerCase().trim() === this.selectedCuisine.toLowerCase().trim()
        )
      );
    }


    // Filtro provincia
    if (this.selectedProvince) {
      filtered = filtered.filter(r => r.province === this.selectedProvince);
    }

    this.filteredRestaurants = filtered;
    this.currentPage = 1;
  }

  onSearchChange() {
    this.filterRestaurants();
  }

onCuisineFilter(cuisine: string) {
  this.selectedCuisine = cuisine === this.selectedCuisine ? '' : cuisine;
  this.filterRestaurants();
}

  // Paginazione
  nextPage() {
    if (this.currentPage * this.pageSize < this.filteredRestaurants.length) {
      this.currentPage++;
    }
  }

  previousPage() {
    if (this.currentPage > 1) {
      this.currentPage--;
    }
  }

  get paginatedRestaurants(): PublicRestaurant[] {
    const startIndex = (this.currentPage - 1) * this.pageSize;
    return this.filteredRestaurants.slice(startIndex, startIndex + this.pageSize);
  }

viewRestaurantMap(restaurantId: string, event?: Event) {
  // Previene la propagazione dell'evento se clicchi sul bottone
  if (event) {
    event.stopPropagation();
  }
  
  console.log('Navigating to restaurant map:', restaurantId);
  
  // USA IL PERCORSO CORRETTO - "customer/restaurant/:restaurantId/map"
  this.router.navigate(['/customer/restaurant', restaurantId, 'map']);
}

  // Utilità per troncare il testo
  truncateText(text: string, maxLength: number): string {
    if (!text) return '';
    if (text.length <= maxLength) return text;
    return text.substring(0, maxLength) + '...';
  }

  // Gestione errori immagini
onImageError(event: Event) {
  const img = event.target as HTMLImageElement;
  this.imageErrorCount++;
  
  // Se abbiamo già provato a caricare il placeholder e fallito, fermati
  if (this.imageErrorCount > this.maxRetries || img.src.includes('placeholder')) {
    img.style.display = 'none';
    return;
  }
  
  img.src = 'assets/images/restaurant-placeholder.jpg';
}


onLogoError(event: Event) {
  const img = event.target as HTMLImageElement;
  img.style.display = 'none';
}

viewRestaurantDetails(restaurantId: string) {
  this.router.navigate(['/customer/restaurant', restaurantId]);
}

  // ---------- GEOGRAFIA ----------
  private loadRegions(): void {
    this.geographyService.getFilteredProvinces().subscribe(provinces => {
      // Estrai regioni uniche, escludendo "Tutte"
      this.regions = [...new Set(provinces.map(p => p.region))].sort();
    });
  }

  // Filtra le province in base alla regione selezionata
filterProvincesByRegion(region: string) {
  this.filteredProvinces = region
    ? this.allProvinces.filter(p => p.region === region)
    : [...this.allProvinces];
}

  // ---------- FILTRI DI DEFAULT: PROVINCIA DELL'UTENTE ----------
private async setDefaultUserProvince(allProvinces: Province[]) {
  const user = this.authService.currentUserValue;
  if (!user) {
    this.filteredProvinces = allProvinces;
    return;
  }

  // 1. Cerca di usare user.province se esiste
  let userProvince = user.province;

  // 2. Se non esiste, fai una query alla tabella users
  if (!userProvince) {
    try {
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('users')
        .select('province')
        .eq('id', user.id)
        .single();

      if (!error && data) {
        userProvince = data.province;
      }
    } catch (err) {
      console.warn('Errore nel recupero provincia utente', err);
    }
  }

  // 3. Imposta i filtri in base alla provincia trovata
  if (userProvince) {
    this.selectedProvince = userProvince;
    const provinceData = allProvinces.find(p => p.code === userProvince);
    if (provinceData) {
      this.selectedRegion = provinceData.region;
      this.filteredProvinces = allProvinces.filter(p => p.region === this.selectedRegion);
    } else {
      this.selectedRegion = '';
      this.filteredProvinces = allProvinces;
    }
  } else {
    this.filteredProvinces = allProvinces;
  }
}

  // ---------- GESTIONE CAMBIO FILTRI ----------
  onRegionChange(region: string): void {
    this.selectedRegion = region;
    // Resetta la provincia quando cambi regione
    this.selectedProvince = '';
    this.filterProvincesByRegion(region);
    this.filterRestaurants();
  }

  onProvinceChange(provinceCode: string): void {
    this.selectedProvince = provinceCode;
    // Opzionale: se selezioni una provincia, aggiorna la regione corrispondente
    if (provinceCode) {
      this.geographyService.getFilteredProvinces().subscribe(provinces => {
        const province = provinces.find(p => p.code === provinceCode);
        if (province) {
          this.selectedRegion = province.region;
          this.filterProvincesByRegion(this.selectedRegion);
        }
        this.filterRestaurants(); 
      });
  } else {
    this.filterRestaurants();   // 👈 e anche qui
  }
}

resetFilters() {
  this.searchQuery = '';
  this.selectedCuisine = '';
  this.selectedRegion = '';
  this.selectedProvince = '';
  this.filteredProvinces = this.allProvinces;
  this.filterRestaurants();
}

  // ---------- FILTRAGGIO ----------
  private applyFilters(): void {
    let filtered = this.restaurants;

    // Filtro per provincia (se selezionata)
    if (this.selectedProvince) {
      filtered = filtered.filter(r => r.province === this.selectedProvince);
    }
    // Se vuoi filtrare anche per regione (indirettamente) puoi farlo, 
    // ma dato che la provincia è più specifica, non serve.

    this.filteredRestaurants = filtered;
  }


  private async loadFloorPlansForCurrentPage() {
  const restaurantsOnPage = this.paginatedRestaurants;
  if (restaurantsOnPage.length === 0) return;

  const restaurantIds = restaurantsOnPage.map(r => r.id).filter(id => id);

  try {
    // Query unica per tutte le mappe dei ristoranti della pagina
    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from('restaurant_floor_plans')
      .select('id, name, restaurant_id')
      .in('restaurant_id', restaurantIds)
      .eq('is_active', true)
      .order('name', { ascending: true });

    if (error) throw error;

    // Raggruppa per restaurant_id
    const map = new Map<string, { id: string; name: string }[]>();
    data?.forEach(fp => {
      if (!map.has(fp.restaurant_id)) {
        map.set(fp.restaurant_id, []);
      }
      map.get(fp.restaurant_id)!.push({ id: fp.id, name: fp.name });
    });

    this.restaurantFloorPlansMap = map;
  } catch (error) {
    console.error('❌ Errore caricamento mappe:', error);
  }
}

}